INSERT INTO notice (title, content, is_critical, view_count, created_at) VALUES
('CardWise v4.0 메이저 업데이트 안내 🚀', '드디어 CardWise v4.0이 출시되었습니다. 게이미피케이션 및 커뮤니티 기능이 대폭 강화되었습니다.', TRUE, 1542, NOW() - INTERVAL '3 days'),
('[점검] 서비스 안정화를 위한 정기 점검 안내', '점검 일시: 2026-03-25 02:00 ~ 05:00. 작업 시간 동안 앱 접속이 불가능합니다.', TRUE, 820, NOW() - INTERVAL '1 day'),
('커뮤니티 이용 규칙 및 에티켓 안내 🪐', '건전한 공유 문화를 위해 바른 언어 사용과 중복 글 지양을 부탁드립니다.', FALSE, 432, NOW() - INTERVAL '4 days'),
('신규 카드 혜택 데이터 업데이트 (2026년 3월)', '주요 7개 카드사의 신규 카드 정보가 데이터베이스에 반영되었습니다.', FALSE, 310, NOW() - INTERVAL '5 days'),
('삼성카드 tap tap O 혜택 변경 안내', '2026년 4월 1일부터 커피 전문점 할인 혜택이 일부 조정될 예정입니다.', FALSE, 520, NOW() - INTERVAL '2 days'),
('[이벤트] 첫 커뮤니티 게시글 작성 시 500XP 증정!', '커뮤니티를 활성화해주세요! 첫 글을 작성하신 모든 분께 보너스 경험치를 드립니다.', TRUE, 940, NOW() - INTERVAL '2 days'),
('프리미엄 구독 요금제 오픈 안내 💎', '더욱 정교한 자산 분석과 독점 혜택을 누릴 수 있는 프리미엄 요금제가 출시되었습니다.', FALSE, 215, NOW() - INTERVAL '1 week'),
('카카오톡 채널 연동 및 알림톡 기능 추가', '이제 카카오톡을 통해 실적 리마인더를 받아보실 수 있습니다.', FALSE, 180, NOW() - INTERVAL '6 days'),
('개인정보 처리방침 개정 알림', '이용 약관 및 개인정보 처리방침이 일부 개정되었습니다. 상세 내용을 확인하시기 바랍니다.', FALSE, 120, NOW() - INTERVAL '10 days'),
('아이폰 앱 위젯 기능 정식 출시 📱', '즐겨찾는 카드의 실적 현황을 바탕화면에서 바로 확인해보세요.', FALSE, 285, NOW() - INTERVAL '4 days');
INSERT INTO faq (category, question, answer, priority) VALUES
('ACCOUNT', '패스워드를 잊어버렸어요.', '로그인 화면의 [비밀번호 찾기]를 통해 등록하신 이메일로 재설정 링크를 받으실 수 있습니다.', 10),
('CARD', '내 카드가 목록에 없어요.', '아직 등록되지 않은 카드라면 [카드 추가 문의] 카테고리로 요청해주시면 24시간 내에 반영해드립니다.', 9),
('SUBSCRIPTION', '구독 해지는 어디서 하나요?', '[설정 > 구독 정보] 탭에서 언제든지 해지가 가능합니다. 남은 기간은 계속 사용하실 수 있습니다.', 8),
('GAMIFICATION', '경험치(XP)는 어떻게 쌓나요?', '로그인, 카드 등록, 커뮤니티 게시글 작성 및 댓글 활동을 통해 XP를 얻으실 수 있습니다.', 7),
('PRIVACY', '데이터 보안은 안전한가요?', '사용자의 모든 금융 데이터는 AES-256 암호화되어 전송 및 저장되며, Supabase의 엄격한 보안을 따릅니다.', 10),
('LEDGER', '해외 결제 건이 원화로만 보여요.', '해외 현지 통화로 기록하고 싶으시면 결제 내역 편집에서 해당 활률 스냅샷을 적용해주시면 됩니다.', 5),
('BENEFIT', '실적 계산이 카드사 앱과 달라요.', '기본적으로 승인 완료 시점 데이터 기반입니다. 매입 전표가 넘어오지 않은 내역은 일시적으로 오차가 발생할 수 있습니다.', 6),
('COMMUNITY', '게시글이 삭제되었어요.', '도배성 글이나 비방글은 시스템 또는 관리자에 의해 자동으로 블라인드 처리될 수 있습니다.', 4),
('BADGE', '배지를 땄는데 레벨이 안 올라요.', '배지 달성 보너스 XP는 획득 시점에 즉시 반영되며, 레벨업은 실시간으로 대시보드에서 확인 가능합니다.', 3),
('OTHER', '고객센터 운영 시간은 어떻게 되나요?', '1:1 문의는 24시간 접수가 가능하며, 답변은 영업일 기준 오전 9시 ~ 오후 6시 사이에 순차적으로 진행됩니다.', 1);
INSERT INTO inquiry (account_id, category, title, content, answer, status, created_at, answered_at) VALUES
('11111111-1111-1111-1111-111111111111', 'BILLING', '중복 결제 내역 문의', '어제 스타벅스에서 결제했는데 가계부 목록에 두 번 찍혀있어요. 하나 삭제 부탁드려요.', '시스템 오류로 일시적으로 중복 표기된 것 같습니다. 한 건을 즉시 삭제 처리해드렸습니다.', 'ANSWERED', NOW() - INTERVAL '1 day', NOW() - INTERVAL '22 hours'),
('11111111-1111-1111-1111-111111111111', 'CARD_INFO', '신규 카드 추가 요청', '이번에 새로 나온 KB 국민 WE:SH 카드가 목록에 없는데 추가해주실 수 있나요?', '요청하신 카드는 현재 데이터 검증 중이며 금일 자정 이전에 추가될 예정입니다. 감사합니다.', 'ANSWERED', NOW() - INTERVAL '2 days', NOW() - INTERVAL '1 day'),
('11111111-1111-1111-1111-111111111111', 'GAMIFICATION', '배지 미획득 오류', '카페를 30번 넘게 갔는데 카페 매니아 배지를 못 받았어요.', NULL, 'PENDING', NOW() - INTERVAL '3 hours', NULL),
('11111111-1111-1111-1111-111111111111', 'OTHER', '다크 모드 지원 여부', '앱이 너무 예쁜데 밤에는 좀 밝네요 다크 모드 계획이 있으신가요?', '네, 현재 로즈 미니멀 톤의 다크 모드 개발이 진행 중입니다. 다음 업데이트를 기대해주세요!', 'ANSWERED', NOW() - INTERVAL '12 hours', NOW() - INTERVAL '5 hours'),
('11111111-1111-1111-1111-111111111111', 'BILLING', '연회비 캐시백 이벤트 확인', '연회비 100% 캐시백 이벤트 대상자가 맞는지 궁금합니다.', NULL, 'PENDING', NOW() - INTERVAL '1 hour', NULL),
('11111111-1111-1111-1111-111111111111', 'CARD_INFO', '카드 이미지 오류', '현대카드 M3 Edition2 이미지가 틀린 것 같아요.', '제보 감사합니다! 즉시 표준 이미지로 수정하였습니다.', 'ANSWERED', NOW() - INTERVAL '3 days', NOW() - INTERVAL '2 days'),
('11111111-1111-1111-1111-111111111111', 'OTHER', '알림톡이 안 와요', '카드 원터치 알림 설정했는데 카톡으로 안 오네요.', NULL, 'PENDING', NOW() - INTERVAL '5 hours', NULL),
('11111111-1111-1111-1111-111111111111', 'GAMIFICATION', 'XP 획득 경로 문의', '오늘 로그인했는데 XP가 안 올라가서 확인 부탁드려요.', '일일 최대 로그인 XP는 1회로 제한됩니다. 이미 획득하신 이력이 있는 점 확인되었습니다.', 'ANSWERED', NOW() - INTERVAL '1 day', NOW() - INTERVAL '1 day'),
('11111111-1111-1111-1111-111111111111', 'BILLING', '수동 결제 입력 방법', '카드가 연동 안 되는 건은 직접 넣고 싶은데 어디서 하나요?', '가계부 메인 화면 우측 하단의 [+] 버튼을 누르시면 수동 입력이 가능합니다.', 'ANSWERED', NOW() - INTERVAL '4 days', NOW() - INTERVAL '4 days'),
('11111111-1111-1111-1111-111111111111', 'CARD_INFO', '카드 혜택 정렬 기준', '혜택이 많은 순서대로 볼 수는 없나요?', NULL, 'PENDING', NOW() - INTERVAL '6 hours', NULL),
('11111111-1111-1111-1111-111111111111', 'OTHER', '탈퇴 방법 문의', '개인적 사정으로 탈퇴하고 싶습니다.', '탈퇴는 [설정 > 계정 > 서비스 해지]에서 하실 수 있습니다. 데이터는 즉시 파기되니 신중히 결정해주세요.', 'ANSWERED', NOW() - INTERVAL '5 days', NOW() - INTERVAL '5 days'),
('11111111-1111-1111-1111-111111111111', 'BILLING', '환율 데이터 출처', '매일 환율이 바뀌는데 어디 데이터를 쓰시는 건가요?', '하나은행 실시간 고시 환율 기반으로 매일 자정에 업데이트 및 저장하고 있습니다.', 'ANSWERED', NOW() - INTERVAL '2 days', NOW() - INTERVAL '2 days'),
('11111111-1111-1111-1111-111111111111', 'OTHER', '앱 로딩이 좀 느려요', '커뮤니티 들어갈 때 로딩 스피너가 너무 오래 보여요.', NULL, 'PENDING', NOW() - INTERVAL '30 minutes', NULL),
('11111111-1111-1111-1111-111111111111', 'GAMIFICATION', '티어 승급 기준', '레벨 20인데 왜 아직 실버인가요?', '골드 티어는 레벨 21부터 시작됩니다. 1레벨만 더 올리시면 승급 가능합니다!', 'ANSWERED', NOW() - INTERVAL '1 day', NOW() - INTERVAL '1 day'),
('11111111-1111-1111-1111-111111111111', 'CARD_INFO', '카드 추천 기능 건의', '제 소비 패턴 분석해서 카드 추천해주는 기능도 만들어주세요!', '현재 데이터 분석 엔진 고도화 중이며 조만간 맞춤형 추천 기능이 추가될 예정입니다. 좋은 제안 감사합니다.', 'ANSWERED', NOW() - INTERVAL '1 week', NOW() - INTERVAL '1 week');
INSERT INTO community_post (account_id, category, title, content, view_count, created_at, tags) VALUES
('11111111-1111-1111-1111-111111111111', 'CARD_HACKS', '편의점 반값 결제하는 법 (비밀 꿀팁) 💡', '특정 요일에 특정 페이로 결제하면 50%까지 할인되더라구요. 다들 아셨나요?', 120, NOW() - INTERVAL '1 day', '["편의점", "할인", "꿀팁"]'),
('11111111-1111-1111-1111-111111111111', 'SAVING_TIPS', '이번 달 무지출 챌린지 7일차 성공! 💰', '식비 방어 대성공입니다. 냉파(냉장고 파먹기)가 최고네요.', 85, NOW() - INTERVAL '12 hours', '["무지출", "절약", "냉파"]'),
('11111111-1111-1111-1111-111111111111', 'QNA', '교통비 많이 나오는 분들 카드 추천 좀요 ❓', '매일 왕복 2시간 통근하는데 알뜰교통카드 말고 좋은 거 있을까요?', 340, NOW() - INTERVAL '2 days', '["교통비", "질문", "카드추천"]'),
('11111111-1111-1111-1111-111111111111', 'FREE', '오늘 월급날인데 가계부 쓰기 싫어요 ㅠㅠ 💬', '월급 들어오자마자 카드값이 다 빠져나가네요. 저만 그런 거 아니죠?', 512, NOW() - INTERVAL '5 hours', '["월급", "텅장", "자유"]'),
('11111111-1111-1111-1111-111111111111', 'CARD_HACKS', '항공 마일리지 적립 끝판왕 카드 대공개', '요즘 여행 많이 가시죠? 대한항공 아시아나 마일리지 쌓기 좋은 카드들만 모았습니다.', 92, NOW() - INTERVAL '3 days', '["마일리지", "여행", "카드"]'),
('11111111-1111-1111-1111-111111111111', 'SAVING_TIPS', '커피값만 아껴도 한 달에 10만원이네요.', '매일 마시는 스타벅스를 편의점 캔커피로 바꿨더니 10만원 넘게 아껴져요!', 128, NOW() - INTERVAL '4 days', '["절약", "커피", "짠테크"]'),
('11111111-1111-1111-1111-111111111111', 'QNA', '해외 직구할 때 유리한 카드 있나요?', '아마존에서 블프 때 쇼핑하려고 하는데 추천 부탁드려요.', 215, NOW() - INTERVAL '6 days', '["직구", "해외결제"]'),
('11111111-1111-1111-1111-111111111111', 'FREE', 'CardWise 레벨 30 달성 인증합니다! 🎉', '드디어 카드 전문가 호칭을 얻었네요. 뿌듯합니다.', 65, NOW() - INTERVAL '1 day', '["레벨업", "인증"]'),
('11111111-1111-1111-1111-111111111111', 'CARD_HACKS', '연회비 없는 프리미엄 카드 찾는 법', '연회비는 없지만 바우처나 라운지 혜택 있는 알짜 카드들입니다.', 145, NOW() - INTERVAL '2 days', '["연회비", "혜택"]'),
('11111111-1111-1111-1111-111111111111', 'SAVING_TIPS', '가계부 쓰면서 돈 모으는 재미에 빠졌어요.', 'CardWise로 관리하니까 매일 들어오게 되네요.', 38, NOW() - INTERVAL '10 hours', '["가계부", "습관"]'),
('11111111-1111-1111-1111-111111111111', 'QNA', '아파트 관리비 할인되는 카드?', '관리비가 너무 올랐어요. 고정비 아끼고 싶어요.', 420, NOW() - INTERVAL '5 days', '["관리비", "고정비"]'),
('11111111-1111-1111-1111-111111111111', 'FREE', '오늘 점심 뭐 드실 건가요?', '날씨가 쌀쌀해서 뜨끈한 국밥이 땡기네요.', 24, NOW() - INTERVAL '1 hour', '["점심", "자유"]'),
('11111111-1111-1111-1111-111111111111', 'CARD_HACKS', '숨겨진 카드 포인트 찾는 법 🪙', '잠자고 있는 카드 포인트가 생각보다 많더라구요. 다들 조회해보세요.', 280, NOW() - INTERVAL '4 days', '["카드포인트", "꿀팁"]'),
('11111111-1111-1111-1111-111111111111', 'SAVING_TIPS', '배달의민족 끊기 3일차 지옥입니다.', '배고픈데 참아야 하느니라... 집밥 해먹고 2만원 아꼈습니다.', 56, NOW() - INTERVAL '15 hours', '["배달", "절약", "집밥"]'),
('11111111-1111-1111-1111-111111111111', 'QNA', '넷플릭스 할인 필수 카드?', '유튜브 프리미엄이랑 넷플릭스 같이 할인되는 거 있나요?', 310, NOW() - INTERVAL '2 days', '["구독료", "넷플릭스"]'),
('11111111-1111-1111-1111-111111111111', 'FREE', '이번 주말 여행 계획 있으신 분?', '강릉 가려고 하는데 맛집 좀 알려주세요!', 42, NOW() - INTERVAL '1 day', '["여행", "자유"]'),
('11111111-1111-1111-1111-111111111111', 'CARD_HACKS', '주유비 80원 할인받는 최강 카드', '기름값 너무 비싼데 이 카드로 주유하면 체감 할인율 높아요.', 198, NOW() - INTERVAL '6 days', '["주유", "할인"]'),
('11111111-1111-1111-1111-111111111111', 'SAVING_TIPS', '커플 통장 대신 커플 카드 추천', '데이트 비용 관리하기 좋은 카드 정리했습니다.', 74, NOW() - INTERVAL '3 days', '["데이트", "공동자금"]'),
('11111111-1111-1111-1111-111111111111', 'QNA', '학생인데 생애 첫 신용카드 뭐가 좋죠?', '대학생도 발급 가능한 혜택 좋은 카드 추천 부탁요.', 256, NOW() - INTERVAL '1 week', '["학생", "신규"]'),
('11111111-1111-1111-1111-111111111111', 'FREE', '반려견이랑 산책 다녀왔어요 🐶', '날씨 좋아서 댕댕이도 신났네요. 다들 힐링하세요!', 15, NOW() - INTERVAL '2 hours', '["반려견", "힐링"]'),
('11111111-1111-1111-1111-111111111111', 'CARD_HACKS', '쇼핑몰 멤버십 연동 혜택 총정리', '쿠팡 와우, 네이버 플러스 멤버십 무료로 쓰는 법', 320, NOW() - INTERVAL '5 days', '["쇼핑", "멤버십"]'),
('11111111-1111-1111-1111-111111111111', 'SAVING_TIPS', '지역화폐 연동해서 써보셨나요?', '카드 혜택이랑 지역화폐 인센티브 같이 받는 전략입니다.', 45, NOW() - INTERVAL '1 day', '["지역화폐", "전략"]'),
('11111111-1111-1111-1111-111111111111', 'QNA', '전월 실적 30만원 맞추는 팁', '딱 2만원 모자란데 어떻게 채우는 게 가장 효율적일까요?', 185, NOW() - INTERVAL '3 days', '["실적", "질문"]'),
('11111111-1111-1111-1111-111111111111', 'FREE', '오늘 저녁은 치킨이다!', '이벤트 당첨돼서 받은 쿠폰으로 먹습니다 캬캬', 32, NOW() - INTERVAL '20 minutes', '["치킨", "자유"]'),
